CREATE TEMP TABLE _bc (asin TEXT, upc TEXT, ean TEXT);

UPDATE india_master_sellers m SET upc = b.upc, ean = b.ean
FROM _bc b WHERE m.asin = b.asin AND (m.upc IS NULL OR m.ean IS NULL);

UPDATE sku_catalog sc SET
  barcode_1 = COALESCE(sc.barcode_1, b.upc),
  barcode_2 = COALESCE(sc.barcode_2, b.ean),
  barcodes = CASE 
    WHEN sc.barcodes IS NULL OR sc.barcodes = '[]'::jsonb THEN
      (SELECT jsonb_agg(x) FROM unnest(ARRAY[b.upc, b.ean]) x WHERE x IS NOT NULL)
    ELSE sc.barcodes
  END
FROM _bc b WHERE sc.asin = b.asin AND (sc.barcode_1 IS NULL OR sc.barcode_1 = '');

DROP TABLE _bc;
